import React, { useState, useRef, useEffect } from "react";
import ReactMarkdown from "react-markdown";

const OWNER_NAME = "Abdy Mohameden";
const SYSTEM_PROMPT = `Tu es un assistant IA personnel et dévoué, créé exclusivement pour ${OWNER_NAME}.
Tu t'adresses toujours directement à ${OWNER_NAME} par son prénom.
Tu réponds en français par défaut, mais tu peux aussi répondre en arabe ou en anglais si ${OWNER_NAME} le souhaite.
Tu es intelligent, chaleureux, précis et toujours disponible pour aider ${OWNER_NAME}.
Tu te souviens qu'il habite à Nouakchott, Mauritanie, et tu adaptes tes réponses à son contexte.`;

const API_URL = "https://openrouter.ai/api/v1/chat/completions";
const FREE_MODEL = "google/gemini-2.0-flash-001";

function formatTime(date) {
  return new Date(date).toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" });
}

function formatDate(date) {
  return new Date(date).toLocaleDateString("fr-FR", { day: "numeric", month: "short" });
}

function TypingDots() {
  return (
    <div className="flex items-center gap-1 px-4 py-3">
      {[0, 1, 2].map((i) => (
        <span key={i} className="w-2 h-2 rounded-full bg-violet-400 animate-bounce" style={{ animationDelay: `${i * 0.15}s` }} />
      ))}
    </div>
  );
}

function Message({ msg }) {
  const isUser = msg.role === "user";
  return (
    <div className={`flex gap-3 ${isUser ? "flex-row-reverse" : "flex-row"} mb-4`}>
      <div className={`flex-shrink-0 w-8 h-8 rounded-xl flex items-center justify-center text-xs font-bold
        ${isUser ? "bg-violet-600 text-white" : "bg-gradient-to-br from-indigo-500 to-purple-600 text-white"}`}>
        {isUser ? "A" : "🤖"}
      </div>
      <div className={`max-w-[75%] flex flex-col gap-1 ${isUser ? "items-end" : "items-start"}`}>
        <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed
          ${isUser ? "bg-violet-600 text-white rounded-tr-sm" : "bg-[#1a1a2e] border border-white/10 text-gray-200 rounded-tl-sm"}`}>
          {isUser ? <p>{msg.content}</p> : <div className="msg-content"><ReactMarkdown>{msg.content}</ReactMarkdown></div>}
        </div>
        <span className="text-xs text-gray-600 px-1">{formatTime(msg.time)}</span>
      </div>
    </div>
  );
}

function generateId() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2);
}

function newConversation() {
  return { id: generateId(), title: "Nouvelle conversation", messages: [], createdAt: Date.now() };
}

export default function App() {
  const [apiKey, setApiKey] = useState(() => localStorage.getItem("abdy_openrouter_key") || "");
  const [keyInput, setKeyInput] = useState(apiKey);
  const [showSettings, setShowSettings] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const [conversations, setConversations] = useState(() => {
    try {
      const saved = localStorage.getItem("abdy_conversations");
      return saved ? JSON.parse(saved) : [newConversation()];
    } catch { return [newConversation()]; }
  });

  const [activeId, setActiveId] = useState(() => {
    try {
      const saved = localStorage.getItem("abdy_conversations");
      if (saved) { const convs = JSON.parse(saved); return convs[0]?.id || null; }
    } catch {}
    return conversations[0]?.id || null;
  });

  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [editingId, setEditingId] = useState(null);
  const [editTitle, setEditTitle] = useState("");
  const bottomRef = useRef(null);
  const inputRef = useRef(null);

  const activeConv = conversations.find((c) => c.id === activeId);

  // Persist conversations
  useEffect(() => {
    localStorage.setItem("abdy_conversations", JSON.stringify(conversations));
  }, [conversations]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [activeConv?.messages, loading]);

  const saveKey = () => {
    localStorage.setItem("abdy_openrouter_key", keyInput);
    setApiKey(keyInput);
    setShowSettings(false);
    setError("");
  };

  const createConversation = () => {
    const conv = newConversation();
    setConversations((prev) => [conv, ...prev]);
    setActiveId(conv.id);
    setInput("");
    setError("");
    inputRef.current?.focus();
  };

  const deleteConversation = (id) => {
    setConversations((prev) => {
      const updated = prev.filter((c) => c.id !== id);
      if (updated.length === 0) {
        const fresh = newConversation();
        setActiveId(fresh.id);
        return [fresh];
      }
      if (activeId === id) setActiveId(updated[0].id);
      return updated;
    });
  };

  const startEdit = (conv) => {
    setEditingId(conv.id);
    setEditTitle(conv.title);
  };

  const saveEdit = (id) => {
    setConversations((prev) => prev.map((c) => c.id === id ? { ...c, title: editTitle || "Sans titre" } : c));
    setEditingId(null);
  };

  const sendMessage = async () => {
    if (!input.trim() || loading || !activeConv) return;
    if (!apiKey) { setError("⚠️ Configure ta clé OpenRouter dans ⚙️"); return; }

    const userMsg = { role: "user", content: input.trim(), time: Date.now() };
    const updatedMessages = [...activeConv.messages, userMsg];

    // Auto-title after first message
    const isFirst = activeConv.messages.length === 0;
    const autoTitle = isFirst ? input.trim().slice(0, 40) + (input.length > 40 ? "…" : "") : activeConv.title;

    setConversations((prev) => prev.map((c) =>
      c.id === activeId ? { ...c, messages: updatedMessages, title: autoTitle } : c
    ));
    setInput("");
    setLoading(true);
    setError("");

    try {
      const res = await fetch(API_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${apiKey}`,
          "HTTP-Referer": "http://localhost:3000",
          "X-Title": "Abdy AI",
        },
        body: JSON.stringify({
          model: FREE_MODEL,
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            ...updatedMessages.map(({ role, content }) => ({ role, content })),
          ],
        }),
      });

      if (!res.ok) { const e = await res.json(); throw new Error(e.error?.message || `Erreur ${res.status}`); }
      const data = await res.json();
      const aiText = data.choices?.[0]?.message?.content || "Désolé, pas de réponse.";
      const aiMsg = { role: "assistant", content: aiText, time: Date.now() };

      setConversations((prev) => prev.map((c) =>
        c.id === activeId ? { ...c, messages: [...updatedMessages, aiMsg] } : c
      ));
    } catch (e) {
      setError(`❌ ${e.message}`);
    } finally {
      setLoading(false);
      inputRef.current?.focus();
    }
  };

  const handleKey = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  return (
    <div className="flex h-screen bg-[#0a0a0f] text-white overflow-hidden">

      {/* ── SIDEBAR ── */}
      <div className={`flex flex-col transition-all duration-300 bg-[#0d0d1a] border-r border-white/10 ${sidebarOpen ? "w-72" : "w-0 overflow-hidden"}`}>
        {/* Sidebar header */}
        <div className="flex items-center justify-between px-4 py-4 border-b border-white/10">
          <div className="flex items-center gap-2">
            <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-violet-500 to-indigo-600 flex items-center justify-center text-xs">🤖</div>
            <span className="font-bold text-sm">Abdy AI</span>
          </div>
          <button onClick={createConversation} className="w-8 h-8 rounded-lg bg-violet-600 hover:bg-violet-500 flex items-center justify-center transition text-lg" title="Nouveau chat">
            +
          </button>
        </div>

        {/* Conversations list */}
        <div className="flex-1 overflow-y-auto py-2 px-2">
          {conversations.map((conv) => (
            <div
              key={conv.id}
              onClick={() => { setActiveId(conv.id); setError(""); }}
              className={`group flex items-center gap-2 px-3 py-2.5 rounded-xl cursor-pointer mb-1 transition
                ${activeId === conv.id ? "bg-violet-600/20 border border-violet-500/30" : "hover:bg-white/5 border border-transparent"}`}>
              <div className="flex-1 min-w-0">
                {editingId === conv.id ? (
                  <input
                    autoFocus
                    value={editTitle}
                    onChange={(e) => setEditTitle(e.target.value)}
                    onBlur={() => saveEdit(conv.id)}
                    onKeyDown={(e) => e.key === "Enter" && saveEdit(conv.id)}
                    onClick={(e) => e.stopPropagation()}
                    className="w-full bg-black/40 border border-violet-500 rounded px-2 py-0.5 text-xs text-white focus:outline-none"
                  />
                ) : (
                  <>
                    <p className="text-xs font-medium truncate text-gray-200">{conv.title}</p>
                    <p className="text-xs text-gray-600 mt-0.5">{formatDate(conv.createdAt)} · {conv.messages.length} msg</p>
                  </>
                )}
              </div>
              {/* Actions */}
              <div className="hidden group-hover:flex items-center gap-1" onClick={(e) => e.stopPropagation()}>
                <button onClick={() => startEdit(conv)} className="w-6 h-6 rounded-md hover:bg-white/10 flex items-center justify-center text-gray-400 hover:text-white text-xs" title="Renommer">✏️</button>
                <button onClick={() => deleteConversation(conv.id)} className="w-6 h-6 rounded-md hover:bg-red-900/40 flex items-center justify-center text-gray-400 hover:text-red-400 text-xs" title="Supprimer">🗑️</button>
              </div>
            </div>
          ))}
        </div>

        {/* Sidebar footer */}
        <div className="px-4 py-3 border-t border-white/10">
          <p className="text-xs text-gray-600 truncate">Gemini 2.0 Flash · OpenRouter</p>
        </div>
      </div>

      {/* ── MAIN ── */}
      <div className="flex flex-col flex-1 min-w-0">
        {/* Header */}
        <header className="flex items-center justify-between px-5 py-3 border-b border-white/10 bg-[#0d0d18]">
          <div className="flex items-center gap-3">
            <button onClick={() => setSidebarOpen(!sidebarOpen)} className="w-8 h-8 rounded-lg bg-white/5 hover:bg-white/10 flex items-center justify-center transition text-gray-400 hover:text-white text-sm">
              {sidebarOpen ? "◀" : "▶"}
            </button>
            <h1 className="font-semibold text-sm text-gray-200 truncate max-w-xs">
              {activeConv?.title || "Nouvelle conversation"}
            </h1>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={createConversation} className="text-xs text-gray-500 hover:text-violet-400 transition px-3 py-1.5 rounded-lg hover:bg-violet-900/20 border border-white/5">
              + Nouveau chat
            </button>
            <button onClick={() => setShowSettings(!showSettings)} className="w-8 h-8 rounded-lg bg-white/5 hover:bg-white/10 flex items-center justify-center transition text-gray-400 hover:text-white">
              ⚙️
            </button>
          </div>
        </header>

        {/* Settings */}
        {showSettings && (
          <div className="bg-[#12121f] border-b border-white/10 px-5 py-4">
            <p className="text-xs text-gray-400 mb-1 font-mono">Clé API OpenRouter</p>
            <p className="text-xs text-green-500 mb-2">✅ Modèle : Gemini 2.0 Flash</p>
            <div className="flex gap-2">
              <input type="password" value={keyInput} onChange={(e) => setKeyInput(e.target.value)}
                placeholder="sk-or-..." className="flex-1 bg-black/30 border border-white/10 rounded-xl px-4 py-2 text-sm text-white focus:outline-none focus:border-violet-500 font-mono" />
              <button onClick={saveKey} className="px-4 py-2 bg-violet-600 hover:bg-violet-500 text-white rounded-xl text-sm font-semibold transition">Sauvegarder</button>
            </div>
          </div>
        )}

        {/* Messages */}
        <main className="flex-1 overflow-y-auto px-6 py-6">
          {activeConv?.messages.length === 0 && (
            <div className="flex flex-col items-center justify-center h-full gap-4 text-center pb-10">
              <div className="text-4xl">💬</div>
              <h2 className="text-lg font-bold text-white">Nouvelle conversation</h2>
              <p className="text-gray-500 text-sm max-w-sm">Pose ta question, Abdy. Je suis là pour t'aider !</p>
              <div className="flex flex-wrap gap-2 justify-center mt-2">
                {["Quelle heure est-il à Nouakchott ?", "Explique-moi React hooks", "Aide-moi à apprendre l'arabe", "Donne-moi une recette mauritanienne"].map((q) => (
                  <button key={q} onClick={() => setInput(q)} className="px-3 py-1.5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-full text-xs text-gray-400 hover:text-white transition">{q}</button>
                ))}
              </div>
            </div>
          )}

          {activeConv?.messages.map((msg, i) => <Message key={i} msg={msg} />)}

          {loading && (
            <div className="flex gap-3 mb-4">
              <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-xs">🤖</div>
              <div className="bg-[#1a1a2e] border border-white/10 rounded-2xl rounded-tl-sm"><TypingDots /></div>
            </div>
          )}

          {error && <div className="mx-auto max-w-md bg-red-900/20 border border-red-500/30 text-red-400 text-sm px-4 py-3 rounded-xl">{error}</div>}
          <div ref={bottomRef} />
        </main>

        {/* Input */}
        <footer className="px-5 py-4 border-t border-white/10 bg-[#0d0d18]">
          <div className="flex gap-3 items-end">
            <textarea ref={inputRef} value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={handleKey}
              placeholder="Pose ta question, Abdy…" rows={1}
              className="flex-1 resize-none bg-white/5 border border-white/10 focus:border-violet-500 rounded-2xl px-4 py-3 text-sm text-white placeholder-gray-600 focus:outline-none transition max-h-36 overflow-y-auto"
              style={{ lineHeight: "1.6" }} />
            <button onClick={sendMessage} disabled={loading || !input.trim()}
              className={`flex-shrink-0 w-11 h-11 rounded-2xl flex items-center justify-center transition text-lg
                ${loading || !input.trim() ? "bg-white/5 text-gray-600 cursor-not-allowed" : "bg-violet-600 hover:bg-violet-500 text-white shadow-lg shadow-violet-900/40 hover:scale-105 active:scale-95"}`}>
              {loading ? "⏳" : "➤"}
            </button>
          </div>
          <p className="text-center text-xs text-gray-700 mt-2">Entrée pour envoyer • Shift+Entrée pour nouvelle ligne</p>
        </footer>
      </div>
    </div>
  );
}
